import { useCallback, useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { useTranslation } from '../i18n/useTranslation'
import { getContactSettings, submitContactForm } from '../api/cms'
import { SUPPORT_EMAIL } from '../config/site'
import { SeoHead } from '../components/SeoHead'
import TurnstileWidget from '../components/TurnstileWidget'
import { defaultLang } from '../i18n/translations'
import './ContactPage.css'

const turnstileSiteKey =
  typeof import.meta.env.VITE_TURNSTILE_SITE_KEY === 'string'
    ? import.meta.env.VITE_TURNSTILE_SITE_KEY.trim()
    : ''

export default function ContactPage() {
  const lang = defaultLang
  const t = useTranslation(lang)
  const [settings, setSettings] = useState(null)
  const [loading, setLoading] = useState(true)
  /** True when GET /contact failed (unknown route, CMS down, wrong API URL) — page still works with defaults */
  const [settingsFromApi, setSettingsFromApi] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [submitSuccess, setSubmitSuccess] = useState(false)
  const [formError, setFormError] = useState('')
  const [form, setForm] = useState({
    name: '',
    email: '',
    subject: '',
    message: '',
    accepts_terms: false,
  })
  const [turnstileToken, setTurnstileToken] = useState('')
  const [turnstileResetKey, setTurnstileResetKey] = useState(0)

  const onTurnstileToken = useCallback((token) => {
    setTurnstileToken(token)
    setFormError('')
  }, [])

  useEffect(() => {
    document.documentElement.lang = lang
  }, [lang])

  useEffect(() => {
    getContactSettings(lang)
      .then((data) => {
        setSettings(data && typeof data === 'object' ? data : {})
        setSettingsFromApi(true)
      })
      .catch((err) => {
        console.warn('[Contact] getContactSettings failed — using defaults:', err?.message || err)
        setSettings({})
        setSettingsFromApi(false)
      })
      .finally(() => setLoading(false))
  }, [lang])

  const subjectOptions = [
    { value: '', label: t('contact.chooseSubject') },
    { value: 'general', label: t('contact.subjectGeneral') },
    { value: 'support', label: t('contact.subjectSupport') },
    { value: 'feedback', label: t('contact.subjectFeedback') },
    { value: 'other', label: t('contact.subjectOther') },
  ]

  function handleChange(e) {
    const { name, value, type, checked } = e.target
    setForm((prev) => ({ ...prev, [name]: type === 'checkbox' ? checked : value }))
    setFormError('')
  }

  async function handleSubmit(e) {
    e.preventDefault()
    if (!form.accepts_terms) {
      setFormError(t('contact.errorTerms'))
      return
    }
    if (turnstileSiteKey && !turnstileToken) {
      setFormError(t('contact.errorTurnstile'))
      return
    }
    setFormError('')
    setSubmitting(true)
    try {
      await submitContactForm({
        name: form.name.trim(),
        email: form.email.trim(),
        subject: form.subject || t('contact.subjectGeneral'),
        message: form.message.trim(),
        accepts_terms: true,
        send_submitter_acknowledgement: true,
        support_inbox_email: SUPPORT_EMAIL,
        ...(turnstileSiteKey ? { cf_turnstile_response: turnstileToken } : {}),
      }, lang)
      setSubmitSuccess(true)
      setForm({ name: '', email: '', subject: '', message: '', accepts_terms: false })
      setTurnstileToken('')
    } catch (err) {
      const msg = err.message || t('contact.errorSend')
      setFormError(msg)
      setTurnstileResetKey((k) => k + 1)
      setTurnstileToken('')
    } finally {
      setSubmitting(false)
    }
  }

  const displayEmail = (settings?.contact_email && String(settings.contact_email).trim()) || SUPPORT_EMAIL

  if (loading) {
    return (
      <div className="contact-page">
        <div className="contact-page-skeleton" aria-busy="true" aria-live="polite">
          <span className="sr-only">Loading</span>
          <div className="contact-page-skeleton-hero" />
          <div className="contact-page-skeleton-grid">
            <div className="contact-page-skeleton-col">
              <div className="contact-page-skeleton-line contact-page-skeleton-line--lg" />
              <div className="contact-page-skeleton-line" />
              <div className="contact-page-skeleton-line contact-page-skeleton-line--short" />
            </div>
            <div className="contact-page-skeleton-col contact-page-skeleton-col--card">
              <div className="contact-page-skeleton-line" />
              <div className="contact-page-skeleton-field" />
              <div className="contact-page-skeleton-field" />
              <div className="contact-page-skeleton-field" />
            </div>
          </div>
        </div>
      </div>
    )
  }

  return (
    <article className="contact-page">
      <SeoHead title={t('contact.title')} description={t('contact.description')} />

      <header className="contact-page-hero">
        <div className="contact-page-hero-bg" aria-hidden="true" />
        <div className="contact-page-inner contact-page-hero-inner">
          <p className="contact-page-hero-kicker">{t('contact.pageKicker')}</p>
          <h1 className="contact-page-hero-title">{t('contact.title')}</h1>
          <p className="contact-page-hero-lead">{t('contact.intro')}</p>
        </div>
      </header>

      <div className="contact-page-inner contact-page-body">
        {!settingsFromApi ? (
          <div className="contact-page-api-notice" role="status">
            {t('contact.settingsUnavailable')}
          </div>
        ) : null}
        <div className="contact-page-grid">
          <aside className="contact-page-aside">
            <div className="contact-page-aside-card">
              <h2 className="contact-page-aside-heading">{t('contact.email')}</h2>
              <a className="contact-page-aside-email" href={`mailto:${displayEmail}`}>
                {displayEmail}
              </a>
              {settings?.contact_phone ? (
                <>
                  <h2 className="contact-page-aside-heading">{t('contact.phone')}</h2>
                  <p className="contact-page-aside-text">{settings.contact_phone}</p>
                </>
              ) : null}
              {settings?.contact_address ? (
                <>
                  <h2 className="contact-page-aside-heading">{t('contact.address')}</h2>
                  <p className="contact-page-aside-text contact-page-aside-text--address">{settings.contact_address}</p>
                </>
              ) : null}
              <p className="contact-page-aside-note">{t('contact.emailNote')}</p>
            </div>
          </aside>

          <div className="contact-page-form-shell">
            {submitSuccess ? (
              <div className="contact-form-success-card" role="status">
                <div className="contact-form-success-icon" aria-hidden="true">✓</div>
                <p className="contact-form-success-title">{t('contact.successMessage')}</p>
                <p className="contact-form-success-sub">{t('contact.successAutoreply')}</p>
                <button
                  type="button"
                  className="contact-form-success-again"
                  onClick={() => {
                    setSubmitSuccess(false)
                    setTurnstileToken('')
                    setTurnstileResetKey((k) => k + 1)
                  }}
                >
                  {t('contact.sendAnother')}
                </button>
              </div>
            ) : (
              <form className="contact-form" onSubmit={handleSubmit} noValidate>
                <h2 className="contact-form-heading">{t('contact.formTitle')}</h2>
                <div className="contact-form-row">
                  <label className="contact-form-label" htmlFor="contact-name">
                    {t('contact.yourName')} <span className="contact-form-required">*</span>
                  </label>
                  <input
                    id="contact-name"
                    type="text"
                    name="name"
                    value={form.name}
                    onChange={handleChange}
                    className="contact-form-input"
                    placeholder={t('contact.yourName')}
                    required
                    autoComplete="name"
                  />
                </div>
                <div className="contact-form-row">
                  <label className="contact-form-label" htmlFor="contact-email">
                    {t('contact.yourEmail')} <span className="contact-form-required">*</span>
                  </label>
                  <input
                    id="contact-email"
                    type="email"
                    name="email"
                    value={form.email}
                    onChange={handleChange}
                    className="contact-form-input"
                    placeholder={t('contact.yourEmail')}
                    required
                    autoComplete="email"
                  />
                </div>
                <div className="contact-form-row">
                  <label className="contact-form-label" htmlFor="contact-subject">
                    {t('contact.subject')} <span className="contact-form-required">*</span>
                  </label>
                  <select
                    id="contact-subject"
                    name="subject"
                    value={form.subject}
                    onChange={handleChange}
                    className="contact-form-select"
                    required
                  >
                    {subjectOptions.map((opt) => (
                      <option key={opt.value || 'empty'} value={opt.value}>
                        {opt.label}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="contact-form-row">
                  <label className="contact-form-label" htmlFor="contact-message">
                    {t('contact.message')} <span className="contact-form-required">*</span>
                  </label>
                  <textarea
                    id="contact-message"
                    name="message"
                    value={form.message}
                    onChange={handleChange}
                    className="contact-form-textarea"
                    placeholder={t('contact.writeMessage')}
                    required
                    rows={5}
                  />
                </div>
                <div className="contact-form-row contact-form-consent">
                  <label className="contact-form-checkbox-label">
                    <input
                      type="checkbox"
                      name="accepts_terms"
                      checked={form.accepts_terms}
                      onChange={handleChange}
                      className="contact-form-checkbox"
                    />
                    <span>
                      {t('contact.iAccept')}{' '}
                      <Link to="/page/terms" className="contact-form-legal-link">
                        {t('contact.termsAndConditions')}
                      </Link>
                      {' & '}
                      <Link to="/page/privacy" className="contact-form-legal-link">
                        {t('contact.legalPrivacy')}
                      </Link>
                    </span>
                  </label>
                </div>
                {turnstileSiteKey ? (
                  <TurnstileWidget
                    key={turnstileResetKey}
                    siteKey={turnstileSiteKey}
                    onTokenChange={onTurnstileToken}
                  />
                ) : null}
                {formError ? (
                  <p className="contact-form-error" role="alert">
                    {formError}
                  </p>
                ) : null}
                <button
                  type="submit"
                  className="contact-form-submit"
                  disabled={submitting}
                >
                  {submitting ? t('contact.sending') : t('contact.sendMessage')}
                </button>
              </form>
            )}
          </div>
        </div>

        <footer className="contact-page-foot">
          <Link to="/" className="contact-page-back-link">{t('contact.backHome')}</Link>
        </footer>
      </div>
    </article>
  )
}
